        scheduleReconnect();
      }
    };

    xhr.onerror = () => {
      onError(new Error("SSE connection failed"));
      scheduleReconnect();
    };

    xhr.send();
  }

  function scheduleReconnect() {
    if (aborted) return;
    setTimeout(connect, 2000);
  }

  connect();
